async function fetchValuationData(ticker){const symbol=YAHOO_SYMBOLS[ticker]||ticker;const apiKey=normalizeApiKey(els.valuationApiKey&&els.valuationApiKey.value);const finnhubKey=normalizeApiKey(els.finnhubApiKey&&els.finnhubApiKey.value);const alphaKey=normalizeApiKey(els.alphaVantageApiKey&&els.alphaVantageApiKey.value);const cacheKey="valuationDataV6:"+symbol+":"+(finnhubKey?"finnhub":apiKey?"fmp":alphaKey?"av":"public");const cached=JSON.parse(localStorage.getItem(cacheKey)||"null");if(cached&&Date.now()-cached.savedAt<10*60*1000)return cached.data;let finnhubError=null;try{const finnhubData=await fetchFinnhubValuationData(symbol,finnhubKey);if(finnhubData){localStorage.setItem(cacheKey,JSON.stringify({savedAt:Date.now(),data:finnhubData}));return finnhubData}}catch(e){finnhubError=e}let fmpError=null;try{const fmpData=await fetchFmpValuationData(symbol,apiKey);if(fmpData){localStorage.setItem(cacheKey,JSON.stringify({savedAt:Date.now(),data:fmpData}));return fmpData}}catch(e){fmpError=e}let alphaError=null;try{const avData=await fetchAlphaVantageValuationData(symbol,alphaKey);if(avData){localStorage.setItem(cacheKey,JSON.stringify({savedAt:Date.now(),data:avData}));return avData}}catch(e){alphaError=e}const modules="price,summaryDetail,defaultKeyStatistics,financialData,incomeStatementHistoryQuarterly,balanceSheetHistoryQuarterly,cashflowStatementHistoryQuarterly";const url="https://query1.finance.yahoo.com/v10/finance/quoteSummary/"+encodeURIComponent(symbol)+"?modules="+modules;let payload=null;try{payload=await fetchYahooJson(url)}catch(e){const prefix=(apiKey?"FMP 실패: "+errorMessage(fmpError)+" / ":"")+(finnhubKey?"Finnhub 실패: "+errorMessage(finnhubError)+" / ":"")+(alphaKey?"Alpha 실패: "+errorMessage(alphaError)+" / ":"");throw new Error(prefix+"Yahoo 실패: HTTP 400 또는 브라우저 차단")}const result=getYahooResult(payload);if(!result){const prefix=(apiKey?"FMP 데이터 없음 / ":"")+(finnhubKey?"Finnhub 데이터 없음 / ":"");throw new Error(prefix+"Yahoo 응답 없음")}const price=result.price||{};const summary=result.summaryDetail||{};const stats=result.defaultKeyStatistics||{};const financial=result.financialData||{};const balance=((result.balanceSheetHistoryQuarterly||{}).balanceSheetStatements||[])[0]||{};const cashflow=((result.cashflowStatementHistoryQuarterly||{}).cashflowStatements||[])[0]||{};const cash=firstNumber(rawValue(financial.totalCash),rawValue(balance.cash),rawValue(balance.cashAndCashEquivalents));const debt=firstNumber(rawValue(financial.totalDebt),rawValue(balance.totalDebt),rawValue(balance.shortLongTermDebtTotal));const operatingCashFlow=rawValue(cashflow.totalCashFromOperatingActivities);const burn=typeof operatingCashFlow==="number"&&operatingCashFlow<0?formatMoney(Math.abs(operatingCashFlow))+"/Q":typeof operatingCashFlow==="number"?"+"+formatMoney(operatingCashFlow)+"/Q":"-";const data={source:"Yahoo Finance",asOf:"Yahoo Finance · "+new Date().toLocaleTimeString("ko-KR",{hour:"2-digit",minute:"2-digit"}),items:[["시총",formatMoney(rawValue(price.marketCap))],["P/S",formatRatio(firstNumber(rawValue(summary.priceToSalesTrailing12Months),rawValue(stats.priceToSalesTrailing12Months)))],["EV/Sales",formatRatio(rawValue(stats.enterpriseToRevenue))],["매출 성장",formatPercent(rawValue(financial.revenueGrowth))],["Gross Margin",formatPercent(rawValue(financial.grossMargins))],["현금",formatMoney(cash)],["부채",formatMoney(debt)],["현금 소진",burn]]};localStorage.setItem(cacheKey,JSON.stringify({savedAt:Date.now(),data:data}));return data}
async function fetchPublicQuoteData(ticker){const symbol=YAHOO_SYMBOLS[ticker]||ticker;const urls=["https://query1.finance.yahoo.com/v7/finance/quote?symbols="+encodeURIComponent(symbol),"https://query2.finance.yahoo.com/v7/finance/quote?symbols="+encodeURIComponent(symbol)];let lastError=null;for(const url of urls){try{const payload=await fetchJsonWithProxy(url,6500);const quote=payload&&payload.quoteResponse&&payload.quoteResponse.result&&payload.quoteResponse.result[0];if(quote)return quote}catch(e){lastError=e}}throw lastError||new Error("공개 시세 응답 없음")}
function buildBaselineValuation(ticker,quote,sourceLabel){
  const base=VALUATION_BASELINES[ticker]||{};
  const price=firstNumber(quote&&quote.regularMarketPrice,quote&&quote.postMarketPrice,quote&&quote.preMarketPrice);
  const marketCap=firstNumber(quote&&quote.marketCap,price&&base.shares?price*base.shares:null);
  const ps=firstNumber(quote&&quote.priceToSalesTrailing12Months,marketCap&&base.sales?marketCap/base.sales:null);
  const ev=marketCap&&typeof base.cash==="number"&&typeof base.debt==="number"?marketCap+base.debt-base.cash:null;
  const evSales=ev&&base.sales?ev/base.sales:null;
  return{source:sourceLabel,asOf:sourceLabel+" · "+new Date().toLocaleTimeString("ko-KR",{hour:"2-digit",minute:"2-digit"}),items:[["시총",formatMoney(marketCap)],["P/S",formatRatio(ps)],["EV/Sales",formatRatio(evSales)],["매출 성장",formatPercent(base.growth)],["Gross Margin",formatPercent(base.gross)],["현금",formatMoney(base.cash)],["부채",formatMoney(base.debt)],["현금 소진","-"]]};
}
async function fetchValuationData(ticker){const symbol=YAHOO_SYMBOLS[ticker]||ticker;const apiKey=normalizeApiKey(els.valuationApiKey&&els.valuationApiKey.value);const finnhubKey=normalizeApiKey(els.finnhubApiKey&&els.finnhubApiKey.value);const alphaKey=normalizeApiKey(els.alphaVantageApiKey&&els.alphaVantageApiKey.value);const cacheKey="valuationDataV7:"+symbol+":"+(finnhubKey?"finnhub":apiKey?"fmp":alphaKey?"av":"public");const cached=JSON.parse(localStorage.getItem(cacheKey)||"null");if(cached&&Date.now()-cached.savedAt<10*60*1000)return cached.data;const save=function(data){localStorage.setItem(cacheKey,JSON.stringify({savedAt:Date.now(),data:data}));return data};try{const finnhubData=await fetchFinnhubValuationData(symbol,finnhubKey);if(finnhubData)return save(finnhubData)}catch(e){console.warn("Finnhub valuation unavailable",e)}try{const fmpData=await fetchFmpValuationData(symbol,apiKey);if(fmpData)return save(fmpData)}catch(e){console.warn("FMP valuation unavailable",e)}try{const avData=await fetchAlphaVantageValuationData(symbol,alphaKey);if(avData)return save(avData)}catch(e){console.warn("Alpha Vantage valuation unavailable",e)}try{const quote=await fetchPublicQuoteData(ticker);return save(buildBaselineValuation(ticker,quote,"공개 시세+최근 재무 기준"))}catch(e){console.warn("public quote unavailable",e);return save(buildBaselineValuation(ticker,null,"최근 재무 기준"))}}
function isSameLocalDate(a,b){return a.getFullYear()===b.getFullYear()&&a.getMonth()===b.getMonth()&&a.getDate()===b.getDate()}
function localDateAttr(date){return date.getFullYear()+"-"+String(date.getMonth()+1).padStart(2,"0")+"-"+String(date.getDate()).padStart(2,"0")}
function nextMarketDays(count){const days=[];const cursor=new Date();cursor.setHours(0,0,0,0);while(days.length<count){const day=cursor.getDay();if(day!==0&&day!==6)days.push(new Date(cursor));cursor.setDate(cursor.getDate()+1)}return days}
function eventForDate(date){return MARKET_EVENT_PATTERNS.find(function(item){return item.match(date)})||MARKET_EVENT_PATTERNS[0]}
function renderMarketCalendar(){const grid=document.querySelector(".calendar-grid");if(!grid)return;const today=new Date();grid.textContent="";nextMarketDays(4).forEach(function(date){const event=eventForDate(date);const article=document.createElement("article");article.className="calendar-day"+(isSameLocalDate(date,today)?" today":"");const month=date.getMonth()+1;const day=date.getDate();article.innerHTML='<time datetime="'+localDateAttr(date)+'"><span>'+month+'월 '+day+'일</span><strong>'+date.toLocaleDateString("ko-KR",{weekday:"short"})+'</strong></time><div><b>'+event.title+'</b><p>'+event.body+'</p></div>';grid.append(article)})}
