function renderMetrics(){const items=state.news.filter(function(x){return x.ticker===state.ticker});els.metricNews.textContent=items.length;els.metricPositive.textContent=items.filter(function(x){return x.sentiment>0}).length;els.metricRisk.textContent=items.filter(function(x){return x.risk>0}).length;const heat=items.reduce(function(s,x){return s+x.importance},0)/Math.max(1,items.length);els.metricHeat.textContent=Math.min(99,Math.round(heat))}
function renderAnalysis(){const items=state.news.filter(function(x){return x.ticker===state.ticker});const avg=items.reduce(function(s,x){return s+x.importance},0)/Math.max(1,items.length);const boost=items.reduce(function(s,x){return s+x.sentiment*6},0);const score=Math.max(20,Math.min(95,Math.round(avg+boost)));els.analysisTitle.textContent=state.ticker+" 종합 점수";els.analysisSummary.textContent=items.length?items.length+"개 뉴스 기준입니다. 뉴스 빈도, 중요도, 호재·리스크 신호를 합산했습니다.":"아직 분석할 뉴스가 없습니다.";els.scoreRing.textContent=score;els.scoreRing.style.background="conic-gradient(var(--green) "+score+"%, #e3e9e5 0)";const factors=[["계약/고객",KEYWORDS.contract],["기술 로드맵",KEYWORDS.tech],["재무/밸류에이션",KEYWORDS.finance],["리스크",KEYWORDS.risk]].map(function(pair){const hits=items.filter(function(item){return pair[1].some(function(w){return item.title.toLowerCase().includes(w)})}).length;return{label:pair[0],hits:hits,value:Math.min(100,25+hits*25)}});els.factorList.textContent="";factors.forEach(function(f){const card=document.createElement("article");card.className="factor";card.innerHTML='<header><strong>'+f.label+'</strong><span>'+f.hits+'건</span></header><div class="bar"><span style="--value:'+f.value+'%"></span></div>';els.factorList.append(card)})}
function renderAlerts(){const items=state.news.filter(function(item){return item.ticker===state.ticker&&item.importance>=Number(els.alertThreshold.value)}).slice(0,5);els.alertPreview.textContent=JSON.stringify({ticker:state.ticker,generatedAt:new Date().toISOString(),channel:"IonQ Radar",webhook:els.webhookTarget.value||null,items:items.map(function(item){return{title:item.translated,summary:item.summary,link:item.link,importance:item.importance}})},null,2)}

